## server/src/config/env.ts

Refactored to ensure `config` is guaranteed to be defined.

```typescript
import { z } from 'zod';
import dotenv from 'dotenv';
import path from 'path';

// Explicitly load .env from root
dotenv.config({ path: path.resolve(process.cwd(), '.env') });

const envSchema = z.object({
  NODE_ENV: z.enum(['development', 'production', 'test']).default('development'),
  PORT: z.string().default('3000'),

  // Database
  DB_HOST: z.string().min(1),
  DB_PORT: z.string().default('3306'),
  DB_USER: z.string().min(1),
  DB_PASSWORD: z.string().optional(), // Allow empty for local dev
  DB_NAME: z.string().min(1),

  // Redis
  REDIS_HOST: z.string().default('localhost'),
  REDIS_PORT: z.string().default('6379'),
  REDIS_PASSWORD: z.string().optional(),

  // Security
  JWT_SECRET: z.string().min(10),
  CORS_ORIGIN: z.string().default('*'),

  // M-Pesa
  MPESA_CONSUMER_KEY: z.string().optional(),
  MPESA_CONSUMER_SECRET: z.string().optional(),
  MPESA_PASSKEY: z.string().optional(),
  MPESA_SHORTCODE: z.string().optional(),
  MPESA_CALLBACK_URL: z.string().optional(),

  // SMTP (Email)
  SMTP_HOST: z.string().optional(),
  SMTP_PORT: z.string().default('587'),
  SMTP_USER: z.string().optional(),
  SMTP_PASS: z.string().optional(),
  FROM_EMAIL: z.string().default('noreply@masuma.africa'),
});

const parsedEnv = envSchema.safeParse(process.env);

if (!parsedEnv.success) {
  console.error('❌ Invalid environment variables:', parsedEnv.error.format());
  process.exit(1);
}

// Export strongly typed config
export const config = parsedEnv.data;
```

## server/src/app.ts

Fixed `compression` import and `config` usage.

```typescript
import 'reflect-metadata';
import express from 'express';
import cors from 'cors';
import helmet from 'helmet';
import compression from 'compression';
import rateLimit from 'express-rate-limit';
import path from 'path';
import { redis } from './config/redis';
import { AppDataSource } from './config/database';
import { config } from './config/env'; 
import { errorHandler } from './middleware/errorHandler'; 
import { ProductService } from './services/productService';

// Routers
import authRoutes from './routes/auth.routes';
import productRoutes from './routes/product.routes';
import inventoryRoutes from './routes/inventory.routes';
import salesRoutes from './routes/sales.routes';
import customerRoutes from './routes/customer.routes';
import statsRoutes from './routes/stats.routes';
import orderRoutes from './routes/order.routes';
import mpesaRoutes from './routes/mpesa.routes';
import blogRoutes from './routes/blog.routes';
import userRoutes from './routes/user.routes'; 
import auditRoutes from './routes/audit.routes'; 
import settingsRoutes from './routes/settings.routes'; 
import quoteRoutes from './routes/quote.routes';
import reportRoutes from './routes/report.routes'; 
import contactRoutes from './routes/contact.routes'; 
import branchRoutes from './routes/branch.routes'; 
import notificationRoutes from './routes/notification.routes'; 
import categoryRoutes from './routes/category.routes';
import healthRoutes from './routes/health.routes';
import exchangeRoutes from './routes/exchange.routes';
import vehicleRoutes from './routes/vehicle.routes';
import uploadRoutes from './routes/upload.routes'; 
import financeRoutes from './routes/finance.routes';

// Services & Specific
import { MpesaService } from './services/mpesaService';
import { z } from 'zod';
import { Order, OrderStatus } from './entities/Order';
import { OrderItem } from './entities/OrderItem';
import { validate } from './middleware/validate';

const app = express();

// Initialize Database
AppDataSource.initialize()
  .then(() => {
    console.log(`✅ Database connected: ${config.DB_NAME} on ${config.DB_HOST}`);
  })
  .catch((err) => {
    console.error('❌ Database connection failed:', err);
    process.exit(1);
  });

// --- Security & Performance Middleware ---
app.use(helmet({
  crossOriginResourcePolicy: { policy: "cross-origin" } 
})); 
app.use(compression()); 
app.use(cors({ origin: config.CORS_ORIGIN }));
app.use(express.json());

// --- Static Files ---
app.use('/uploads', express.static(path.join(process.cwd(), 'uploads')));

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, 
  max: 300, 
});
app.use('/api', limiter);

// --- Mount Modular Routes ---
app.use('/api/auth', authRoutes);
app.use('/api/products', productRoutes); 
app.use('/api/inventory', inventoryRoutes);
app.use('/api/sales', salesRoutes);
app.use('/api/customers', customerRoutes);
app.use('/api/admin/stats', statsRoutes);
app.use('/api/orders', orderRoutes);
app.use('/api/mpesa', mpesaRoutes);
app.use('/api/blog', blogRoutes);
app.use('/api/users', userRoutes); 
app.use('/api/audit-logs', auditRoutes); 
app.use('/api/settings', settingsRoutes); 
app.use('/api/quotes', quoteRoutes);
app.use('/api/reports', reportRoutes);
app.use('/api/contact', contactRoutes); 
app.use('/api/branches', branchRoutes); 
app.use('/api/notifications', notificationRoutes); 
app.use('/api/categories', categoryRoutes);
app.use('/api/health', healthRoutes);
app.use('/api/exchange-rates', exchangeRoutes);
app.use('/api/vehicles', vehicleRoutes);
app.use('/api/upload', uploadRoutes);
app.use('/api/finance', financeRoutes);

// --- Legacy / Specific Routes (M-Pesa) ---
const mpesaOrderSchema = z.object({
  customerName: z.string().min(2),
  customerEmail: z.string().email(),
  customerPhone: z.string().min(10),
  shippingAddress: z.string().optional(),
  items: z.array(z.object({ 
    productId: z.string(), 
    quantity: z.number().min(1), 
    price: z.number()
  }))
});

app.post('/api/mpesa/pay', validate(mpesaOrderSchema), async (req: any, res: any) => {
  try {
    const { customerName, customerEmail, customerPhone, shippingAddress, items } = req.body;
    const totalAmount = items.reduce((sum: number, item: any) => sum + (item.price * item.quantity), 0);

    const orderRepo = AppDataSource.getRepository(Order);
    const order = new Order();
    order.orderNumber = `ORD-${Date.now()}`;
    order.customerName = customerName;
    order.customerEmail = customerEmail;
    order.customerPhone = customerPhone;
    order.shippingAddress = shippingAddress || 'Walk-in / Pickup';
    order.totalAmount = totalAmount;
    order.status = OrderStatus.PENDING;
    order.items = items.map((i: any) => {
      const item = new OrderItem();
      item.product = { id: i.productId } as any;
      item.quantity = i.quantity;
      item.price = i.price;
      return item;
    });

    await orderRepo.save(order);
    await MpesaService.initiateStkPush(order.id, customerPhone, totalAmount);

    res.status(201).json({ 
      message: 'STK Push initiated', 
      orderId: order.id,
      phone: customerPhone 
    });
  } catch (error: any) {
    console.error(error);
    res.status(400).json({ error: error.message || 'Payment initiation failed' });
  }
});

app.post('/api/mpesa/callback', async (req, res) => {
  try {
    await MpesaService.handleCallback(req.body);
    res.json({ result: 'ok' });
  } catch (error) {
    console.error('Callback Error', error);
    res.status(500).json({ error: 'Callback failed' });
  }
});

app.get('/api/orders/:id/status', async (req, res) => {
  try {
    const orderRepo = AppDataSource.getRepository(Order);
    const order = await orderRepo.findOne({
      where: { id: req.params.id },
      select: ['status']
    });
    if (!order) return res.status(404).json({ error: 'Order not found' });
    res.json({ status: order.status });
  } catch (error) {
    res.status(500).json({ error: 'Server error' });
  }
});

// Sitemap
app.get('/sitemap.xml', async (req, res) => {
  try {
    const products = await ProductService.getAllProductIdsForSitemap();
    const baseUrl = 'https://masuma.africa/product';
    let xml = `<?xml version="1.0" encoding="UTF-8"?><urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">`;
    products.forEach(p => {
      xml += `<url><loc>${baseUrl}/${p.id}</loc><changefreq>weekly</changefreq><priority>0.8</priority></url>`;
    });
    xml += `</urlset>`;
    res.header('Content-Type', 'text/xml');
    res.send(xml);
  } catch (error) {
    res.status(500).end();
  }
});

// 404 Handler
app.use((req, res) => {
    res.status(404).json({ error: 'Route not found' });
});

// Global Error Handler
app.use(errorHandler as any);

const PORT = config.PORT;
const server = app.listen(PORT, () => {
  console.log(`🚀 Server running on port ${PORT}`);
});

// Graceful Shutdown
const shutdown = async () => {
    console.log('🛑 Shutting down server...');
    server.close(async () => {
        if (AppDataSource.isInitialized) {
            await AppDataSource.destroy();
            console.log('Database connection closed.');
        }
        redis.disconnect();
        console.log('Redis connection closed.');
        process.exit(0);
    });
};

process.on('SIGTERM', shutdown);
process.on('SIGINT', shutdown);
```

## server/src/routes/health.routes.ts

Fixed `process` casting.

```typescript
import { Router } from 'express';
import { AppDataSource } from '../config/database';
import { redis } from '../config/redis';

const router = Router();

router.get('/', async (req, res) => {
    const health = {
        server: 'Online',
        database: 'Unknown',
        redis: 'Unknown',
        uptime: (process as any).uptime(),
        timestamp: new Date()
    };

    // Check DB
    try {
        if (AppDataSource.isInitialized) {
            health.database = 'Connected';
        } else {
            health.database = 'Disconnected';
        }
    } catch (e) {
        health.database = 'Error';
    }

    // Check Redis
    try {
        if (redis.status === 'ready') {
            health.redis = 'Connected';
        } else {
            health.redis = redis.status;
        }
    } catch (e) {
        health.redis = 'Error';
    }

    const status = (health.database === 'Connected' && health.redis === 'Connected') ? 200 : 503;
    res.status(status).json(health);
});

export default router;
```

